/// # Safety
///
/// `name` must be a valid pointer.
#[deprecated]
#[inline]
pub unsafe fn AddFolderDescriptor(
    fold_type: FolderType,
    flags: FolderDescFlags,
    fold_class: FolderClass,
    fold_location: FolderLocation,
    badge_signature: OSType,
    badge_type: OSType,
    name: ConstStrFileNameParam,
    replace_flag: bool,
) -> OSErr {
    extern "C-unwind" {
        fn AddFolderDescriptor(
            fold_type: FolderType,
            flags: FolderDescFlags,
            fold_class: FolderClass,
            fold_location: FolderLocation,
            badge_signature: OSType,
            badge_type: OSType,
            name: ConstStrFileNameParam,
            replace_flag: Boolean,
        ) -> OSErr;
    }
    let replace_flag = replace_flag as _;
    unsafe {
        AddFolderDescriptor(
            fold_type,
            flags,
            fold_class,
            fold_location,
            badge_signature,
            badge_type,
            name,
            replace_flag,
        )
    }
}

